1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	};
21	
22	const FIRST_INSURANCE_SURCHARGE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
26	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
27	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
28	
29	const quotePremium = (items: Item[]): number => {
30	  const itemsPremium = items.reduce(
31	    (sum, item) => sum + BASE_PREMIUM[item.type] * (1 + FIRST_INSURANCE_SURCHARGE),
32	    0
33	  );
34	  return roundPremiumUp(itemsPremium + PROCESSING_FEE);
35	};
36	
37	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
38	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
39	  return { results };
40	};
