18	    const out = runScenario({
19	      customer: { yearsWithMHPCO: 0 },
20	      steps: [
21	        {
22	          op: "quote",
23	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
24	        },
25	      ],
26	    });
27	    expect(out.results[0]).toEqual({ premium: 115 });
28	  });
